UPDATE ecm_busi_statistics
SET busi_number = #{item.busiNumber},file_number = #{item.fileNumber}, file_size = #{item.fileSize}
WHERE org_code = #{item.orgCode}
    and app_code = #{item.appCode}
    and stats_date = #{item.statsDate}

