mapper.update:
MERGE INTO ecm_busi_statistics T1 USING (
SELECT #{item.busiNumber} AS busi_number, #{item.fileNumber} AS file_number, #{item.fileSize} AS file_size, #{item.orgCode} AS org_code, #{item.appCode} AS app_code, #{item.statsDate} AS stats_date FROM DUAL
) T2 ON ( T1.org_code = T2.org_code AND T1.app_code = T2.app_code AND T1.stats_date = T2.stats_date ) WHEN MATCHED THEN UPDATE SET T1.busi_number = T2.busi_number, T1.file_number = T2.file_number, T1.file_size = T2.file_size

