SUM(busi_number) AS count FROM ecm_busi_statistics
create_time >= #{createTimeStart} AND create_time <= #{createTimeEnd}
AND org_code IN
#{item}
AND app_code IN
#{item}
GROUP BY app_code, -- 【关键修改】GROUP BY 必须与 SELECT 中的表达式一致 TRUNC(create_time, 'MM')

